const docs = defineCollection({
  loader: glob({ base: './src/content/docs', pattern: '**/*.{md,mdx}' }),
  schema: () =>
    z.object({
      title: z.string().max(60),
      description: z.string().max(160),
      publishDate: z.coerce.date().optional(),
      updatedDate: z.coerce.date().optional(),
      tags: z.array(z.string()).default([]).transform(removeDupsAndLowerCase),
      draft: z.boolean().default(false),
      // Special fields
      order: z.number().default(999)
    })
})

React.useEffect(() => {
		if (!isDistractionFree) return;

		const handleKeyDown = (e: KeyboardEvent) => {
			if (e.key === "Escape") {
				e.preventDefault();
				e.stopPropagation();
				setIsDistractionFree(false);
			}
		};

		document.addEventListener("keydown", handleKeyDown, { capture: true });
		return () => document.removeEventListener("keydown", handleKeyDown, { capture: true });
	}, [isDistractionFree]);

const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
	const files = e.target.files;
	const file = files?.[0];
	if (file) {
		if (activeProvider === "local") {
			uploadLocalMutation.mutate(file);
		} else if (activeProviderInfo?.capabilities.upload) {
			uploadProviderMutation.mutate({ providerId: activeProvider, file });
		}
	}
	if (fileInputRef.current) {
		fileInputRef.current.value = "";
	}
};

React.useEffect(() => {
		const params = new URLSearchParams(window.location.search);
		const errorParam = params.get("error");
		const message = params.get("message");

		if (errorParam) {
			setUrlError(message || `Authentication error: ${errorParam}`);
			// Clean up URL
			window.history.replaceState({}, "", window.location.pathname);
		}
	}, []);

{
  APP_BLOG.isRelatedPostsEnabled ? (
    <BlogHighlightedPosts
      classes={{
        container:
          'pt-0 lg:pt-0 md:pt-0 intersect-once intersect-quarter motion-safe:md:opacity-0 motion-safe:md:intersect:animate-fade',
      }}
      title="Related Posts"
      linkText="View All Posts"
      linkUrl={getBlogPermalink()}
      postIds={relatedPosts.map((post) => post.id)}
    />
  ) : null
}

return rss({
	title: siteConfig.title,
	description: siteConfig.subtitle || "No description",
	site: context.site ?? "https://firefly.cuteleaf.cn",
	customData: `<templateTheme>Firefly</templateTheme>
	<templateThemeVersion>${pkg.version}</templateThemeVersion>
	<templateThemeUrl>https://github.com/CuteLeaf/Firefly</templateThemeUrl>
	<lastBuildDate>${formatDateI18nWithTime(new Date())}</lastBuildDate>`,
	items: feedItems,
});

const handleAddCustomLink = (e: React.FormEvent<HTMLFormElement>) => {
	e.preventDefault();
	setAddError(null);
	const formData = new FormData(e.currentTarget);
	const labelVal = formData.get("label");
	const urlVal = formData.get("url");
	const targetVal = formData.get("target");
	createMutation.mutate({
		type: "custom",
		label: typeof labelVal === "string" ? labelVal : "",
		customUrl: typeof urlVal === "string" ? urlVal : "",
		target: (typeof targetVal === "string" ? targetVal : "") || undefined,
	});
};

const handleCreate = (e: React.FormEvent<HTMLFormElement>) => {
	e.preventDefault();
	setCreateError(null);
	const formData = new FormData(e.currentTarget);
	const nameVal = formData.get("name");
	const name = typeof nameVal === "string" ? nameVal : "";
	const labelVal = formData.get("label");
	const label = typeof labelVal === "string" ? labelVal : "";
	createMutation.mutate({ name, label, locale: activeLocale });
};

const handleCreateArea = (e: React.FormEvent<HTMLFormElement>) => {
	e.preventDefault();
	setCreateAreaError(null);
	const formData = new FormData(e.currentTarget);
	const nameVal = formData.get("name");
	const labelVal = formData.get("label");
	const descVal = formData.get("description");
	createAreaMutation.mutate({
		name: typeof nameVal === "string" ? nameVal : "",
		label: typeof labelVal === "string" ? labelVal : "",
		description: typeof descVal === "string" ? descVal : "",
	});
};

const iconData = getIconData(collection, iconName ?? setName);
// Missing icon from the icon collection
if (!iconData) {
  const err = new AstroIconError(`Unable to locate "${name}" icon!`);
  if (import.meta.env.DEV) {
    const [maybeStar] = include[setName];
    if (maybeStar === "*" || include[setName].includes(iconName)) {
      err.hint = `The "${setName}" set does not include an icon named "${iconName}".\n\nIs this a typo?`;
    } else {
      err.hint = `The "${setName}" set is not configured to include an icon named "${iconName}".\n\nDo you need to add it to your configuration?`;
    }
  }
  throw err;
}

const providerTabs = React.useMemo(() => {
		const tabs: Array<{ id: string; name: string; icon?: string }> = [
			{ id: "local", name: t`Library`, icon: undefined },
		];
		if (providers) {
			for (const p of providers) {
				if (p.id !== "local") {
					tabs.push({ id: p.id, name: p.name, icon: p.icon });
				}
			}
		}
		return tabs;
	}, [providers, t]);

const activeProviderInfo = React.useMemo(() => {
		if (activeProvider === "local") {
			return {
				id: "local",
				name: "Library",
				icon: undefined,
				capabilities: { browse: true, search: false, upload: true, delete: true },
			} as MediaProviderInfo;
		}
		return providers?.find((p) => p.id === activeProvider);
	}, [activeProvider, providers]);

const { data: providerData, isLoading: providerLoading } = useQuery({
	queryKey: ["provider-media", activeProvider, filters?.join(",") ?? "", searchQuery],
	queryFn: () =>
		fetchProviderMedia(activeProvider, {
			mimeType: filters,
			limit: 50,
			query: searchQuery || undefined,
		}),
	enabled: open && !localOnly && activeProvider !== "local",
});

React.useEffect(() => {
		if (!editor) return;
		const storage = (editor.storage as unknown as Record<string, Record<string, unknown>>).image;
		if (!storage) return;
		storage.onOpenBlockSidebar = (panel: BlockSidebarPanel) => {
			onBlockSidebarOpenRef.current?.(panel);
		};
		storage.onCloseBlockSidebar = () => {
			onBlockSidebarCloseRef.current?.();
		};
		return () => {
			storage.onOpenBlockSidebar = null;
			storage.onCloseBlockSidebar = null;
		};
	}, [editor]);

const providerTabs = React.useMemo(() => {
		const tabs: Array<{ id: string; name: string; icon?: string }> = [
			{ id: "local", name: "Library", icon: undefined },
		];
		if (providers && !localOnly) {
			for (const p of providers) {
				if (p.id !== "local") {
					tabs.push({ id: p.id, name: p.name, icon: p.icon });
				}
			}
		}
		return tabs;
	}, [providers, localOnly]);

React.useEffect(() => {
		if (activeContentKeyRef.current === contentKey) {
			activeOnChangeRef.current = onChange;
			return;
		}
		flushPendingDraft();
		activeContentKeyRef.current = contentKey;
		activeOnChangeRef.current = onChange;
		setDraft(propDraft);
		currentDraftRef.current = propDraft;
		lastPropSnapshotRef.current = propSnapshot;
		lastEmittedSnapshotRef.current = propSnapshot;
	}, [contentKey, flushPendingDraft, onChange, propDraft, propSnapshot]);

if (!currentUser || currentUser.role < ROLE_ADMIN) {
	return (
		<div className="flex items-center justify-center min-h-[50vh]">
			<div className="text-center">
				<h1 className="text-2xl font-bold">{t`Access denied`}</h1>
				<p className="mt-2 text-kumo-subtle">{t`You need admin permissions to manage byline schema.`}</p>
			</div>
		</div>
	);
}

return (
	<div className="flex-1 rounded-lg border border-kumo-line p-4">
		<div className="text-sm text-kumo-subtle">{item.label}</div>
		<div className="mt-1 flex items-baseline gap-2">
			<span className="text-2xl font-bold text-kumo-default">{item.value}</span>
			{TrendIcon && (
				<span className={cn("flex items-center", trend.color)}>
					<TrendIcon size={16} />
				</span>
			)}
		</div>
		{item.description && <div className="mt-1 text-sm text-kumo-subtle">{item.description}</div>}
	</div>
);

const installMutation = useMutation({
	mutationFn: () =>
		installMarketplacePlugin(pluginId, {
			version: plugin?.latestVersion?.version,
		}),
	onSuccess: () => {
		setShowConsent(false);
		void queryClient.invalidateQueries({ queryKey: ["plugins"] });
		void queryClient.invalidateQueries({ queryKey: ["manifest"] });
		void queryClient.invalidateQueries({ queryKey: ["marketplace"] });
	},
});

if (statusError) {
	return (
		<div className="min-h-screen flex items-center justify-center bg-kumo-base">
			<div className="text-center">
				<h1 className="text-xl font-bold text-kumo-danger">{t`Error`}</h1>
				<p className="mt-2 text-kumo-subtle">
					{statusError instanceof Error ? statusError.message : t`Failed to load setup`}
				</p>
			</div>
		</div>
	);
}

const reorderMutation = useMutation({
	mutationFn: ({ areaName, widgetIds }: { areaName: string; widgetIds: string[] }) =>
		reorderWidgets(areaName, widgetIds),
	onSuccess: () => {
		void queryClient.invalidateQueries({ queryKey: ["widget-areas"] });
	},
	onError: (error: Error) => {
		toastManager.add({
			title: t`Error reordering widgets`,
			description: error.message,
			type: "error",
		});
	},
});

if (isLoading) {
	return (
		<div className="space-y-6 animate-pulse">
			<div className="h-6 w-48 rounded bg-kumo-tint" />
			<div className="aspect-video max-w-2xl rounded-lg bg-kumo-tint" />
			<div className="space-y-3">
				<div className="h-4 w-64 rounded bg-kumo-tint" />
				<div className="h-4 w-96 rounded bg-kumo-tint" />
			</div>
		</div>
	);
}
